actions.menu:
function TaskDialog()
this:AddTalk("<p><n color=\"255,255,255,0\">(GetName)</n><n></n><n color=\"255,0,255,255\"> 你好！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">开放时间：</n></p>");
this:AddTalk("<p><n color=\"255,0,255,255\">每天19:00-19:30开放龙脉争夺赛！此项活动仅限组队进入，非单人比赛！</n></p>");
this:AddTalk("<p><n color=\"255,0,255,0\">游戏规则：</n></p>");
this:AddTalk("<p><n color=\"255,255,255,0\">玩家组队进入争夺地图中央的龙脉积分旗，那个团队砍倒积分旗(刷新时间10秒刷新)，团队将获得比赛积分牌，积分牌可右键兑换物品！</n></p>");
this:AddTalk("<p><n color=\"255,255,0,0\">温馨提示：</n></p>");
this:AddTalk("<p><n color=\"255,255,0,255\">队伍有人死亡，可在当前地图复活！此项比赛不区分国家为世界团队比赛！</n></p>");
this:AddTaskCmdItem("参加龙脉争夺赛(0)", "v5130", 1000, 1)
this:AddDialogItem("离开","MainDialog")
end

